INSERT INTO `oJegmj1Sz_options` VALUES("71834","_transient_elementor_unread_notifications_2","a:21:{i:0;s:15:\"components-3.35\";i:1;s:10:\"one-launch\";i:2;s:16:\"atomic-tabs-3.34\";i:3;s:17:\"interactions-3.34\";i:4;s:22:\"variables-manager-3.33\";i:5;s:15:\"custom-css-3.33\";i:6;s:15:\"blend-mode-3.33\";i:7;s:14:\"transform-3.32\";i:8;s:18:\"size-variable-3.32\";i:9;s:16:\"transitions-3.32\";i:10;s:14:\"variables-3.31\";i:11;s:12:\"filters-3.31\";i:12;s:14:\"ally-assistant\";i:13;s:12:\"classes-3.31\";i:14;s:15:\"attributes-3.31\";i:15;s:19:\"cloud-websites-3.30\";i:16;s:17:\"ally-notification\";i:17;s:15:\"ai-site-planner\";i:18;s:20:\"image-optimizer-3.19\";i:19;s:20:\"5-star-rating-prompt\";i:20;s:23:\"site-mailer-introducing\";}","off");
