INSERT INTO `oJegmj1Sz_postmeta` VALUES("141","125","_elementor_data","[{\"id\":\"1e562999\",\"elType\":\"container\",\"settings\":[],\"elements\":[{\"id\":\"9f2c0cb\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<!-- wp:paragraph -->\\n<p>CIAC (Centre d\\u2019 intervention et d\\u2019Action Communautaire) is a National NGO: a non-profit making, non-governmental organization with its head office in Kigali city (Kicukiro District. It operates in all provinces of Rwanda. CIAC was established in June 2022.<\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:paragraph -->\\n<p><strong>Mission:<\\/strong><\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:paragraph -->\\n<p>CIAC\\u2019s mission is to contribute to the socio-economic development of Rwandan communities by improving livelihood through efficient use of natural resources and promoting environmentally friendly agriculture for sustainable development.<\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:paragraph -->\\n<p><strong>Objectives of the Organization<\\/strong>:<\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:list -->\\n<ul><!-- wp:list-item -->\\n<li>Fight against violence in families by leading group discussions with the aim of analysing and providing adequate solutions<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>Install in the population the culture of working in their family plans based on a schedule based on the National strategies plan of the\\u00a0\\u00a0 country<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>Protect natural resources and promote agricultural techniques which are environmentally friendly.<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>Promote hygiene and sanitation through the development and management of water and sanitation infrastructures and increase the number of accesses to clean water and sanitation facilities.<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>Promote gender equality between men and women, I.C.T and entrepreneurship by women and youth based to\\u00a0\\u00a0 speed\\u00a0\\u00a0\\u00a0 up sustainable development\\u00a0\\u00a0<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>Promote research and education based on philosophy and culture for knowing poverty causes and eradication strategies.<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>To promote child rights, Education, child labor, etc\\u2026<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>To promote humanitarian actions from vulnerability to disasters, war or epidemics.<\\/li>\\n<!-- \\/wp:list-item --><\\/ul>\\n<!-- \\/wp:list -->\"},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false},{\"id\":\"78c60099\",\"elType\":\"container\",\"settings\":[],\"elements\":[{\"id\":\"5373eceb\",\"elType\":\"widget\",\"settings\":[],\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false}]");
