INSERT INTO `oJegmj1Sz_postmeta` VALUES("211","139","_elementor_data","[{\"id\":\"295bceab\",\"elType\":\"container\",\"settings\":[],\"elements\":[{\"id\":\"58ba01bf\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<!-- wp:paragraph -->\\n<p><a><strong>Organisational background and capacity<\\/strong><\\/a><\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:paragraph -->\\n<p>CIAC has been established in January 2022 with the overall goal of contributing to the promotion of Rwandan communities by improving livelihood through efficient use of natural resources and promoting environmentally friendly agriculture for sustainable development.<\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:paragraph -->\\n<p>CIAC is a non-profit making non-governmental organization based in Kigali city and it is operating in Rwanda CIAC is serving small farmers, especially women and youth cooperatives.<\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:paragraph -->\\n<p><strong>CIAC\\u2019s intervention domains<\\/strong>:<\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:list -->\\n<ul><!-- wp:list-item -->\\n<li>Environment management.<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>Climate change adaptation and mitigation .<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>Conflict management<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>Economic development.<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>Good governance<\\/li>\\n<!-- \\/wp:list-item --><\\/ul>\\n<!-- \\/wp:list --><!-- wp:paragraph -->\\n<p><strong>Organizational structure:<\\/strong><\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:paragraph -->\\n<p>The management structure of CIAC is composed of the General Assembly, the Board of Directors, and the Coordination Unit which designs and coordinates all project activities.<\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:paragraph -->\\n<p>CIAC has a management committee that follows regularly the use of funds as they are acquired from various donors for the implementation of different projects, CIAC manages those funds according to their source and the norms of the donor. The internal financial and technical reports are produced monthly, quarterly, and annually. The external audit is made annually and other reports are made when needed or according to the convention with the donors.<\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:paragraph -->\\n<p>All reports are made at the level of coordination and approved by the Representative of CIAC.\\u00a0<\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:paragraph -->\\n<p><strong>Previous\\u00a0\\u00a0 and current activities of CIAC include:<\\/strong><\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:list -->\\n<ul><!-- wp:list-item -->\\n<li>Conflict reduction among the farmer family in the Mugina sector<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>Provision of improved cooking stoves to small farmers in Kayonza District with AGROPLAST Lts<\\/li>\\n<!-- \\/wp:list-item --><!-- wp:list-item -->\\n<li>Tree planting in Rukeri landscape.<\\/li>\\n<!-- \\/wp:list-item --><\\/ul>\\n<!-- \\/wp:list -->\"},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false}]");
