e>\\n<!-- \\/wp:image --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:group --><!-- wp:group {\\\"style\\\":{\\\"spacing\\\":{\\\"margin\\\":{\\\"top\\\":\\\"0px\\\",\\\"bottom\\\":\\\"0px\\\"},\\\"padding\\\":{\\\"top\\\":\\\"20px\\\",\\\"right\\\":\\\"20px\\\",\\\"bottom\\\":\\\"20px\\\",\\\"left\\\":\\\"20px\\\"}}},\\\"backgroundColor\\\":\\\"white\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group has-white-background-color has-background\\\" style=\\\"margin-top: 0px; margin-bottom: 0px; padding: 20px;\\\"><!-- wp:heading {\\\"textAlign\\\":\\\"center\\\",\\\"level\\\":4,\\\"style\\\":{\\\"typography\\\":{\\\"letterSpacing\\\":\\\"1px\\\"}},\\\"fontSize\\\":\\\"regular\\\"} -->\\n<h4 class=\\\"wp-block-heading has-text-align-center has-regular-font-size\\\" style=\\\"letter-spacing: 1px;\\\"><strong>Drocelle Musabyimana<\\/strong><\\/h4>\\n<!-- \\/wp:heading --><!-- wp:paragraph {\\\"align\\\":\\\"center\\\",\\\"style\\\":{\\\"spacing\\\":{\\\"margin\\\":{\\\"top\\\":\\\"10px\\\"}}},\\\"textColor\\\":\\\"primary\\\"} -->\\n<p class=\\\"has-text-align-center has-primary-color has-text-color\\\" style=\\\"margin-top: 10px;\\\"><strong><em>President of the BoD , founder and Legal Representative<\\/em><\\/strong><\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:details {\\\"align\\\":\\\"wide\\\"} --><details class=\\\"wp-block-details alignwide\\\">\\n<summary><strong>Email:<\\/strong><br \\/>mudrocelle@gmail.com<br \\/><strong>Mobile\\/WhatsApp:<\\/strong><br \\/>+250 785 507 355 (Rw)<strong><br \\/>Skype Name:<\\/strong><br \\/>Drocelle Musabyimana<br \\/><strong>Languages:\\u00a0<\\/strong><br \\/>English, French, Kinyarwanda<\\/summary>\\n<!-- wp:paragraph {\\\"placeholder\\\":\\\"Type \\/ to add a hidden block\\\"} -->\\n<p>\\u00a0<\\/p>\\n<!-- \\/wp:paragraph --><\\/details><!-- \\/wp:details --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:column --><!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:group {\\\"className\\\":\\\"shadow\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group shadow\\\"><!-- wp:paragraph -->\\n<p>Drocelle is a Water and Environmental Engineer and Master\\u2019s student in Environmental Science ahead to completion. She uses her skills to contribute to the sustainable development of Africa, combining them with her interest in small farmer empowerment, wealth equality and financial inclusion. She believes that small farmers in Africa are the key to achieving sustainable development, for which a bottom-up approach is crucial. She is currently works with DIBcoop, an International Business development as Director Rwanda Office and she has previous worked with SHER-Rwanda, MDF among other where she gained experience in natural resource management, environmental protection, working with farmers and in construction. She contributes to the DIBcoop team in Rwanda by supporting community engagement processes, developing and implementing integrated water catchment plans, and assisting with M&amp;E reporting.<\\/p>\\n<!-- \\/wp:paragraph --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:column --><!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:group {\\\"className\\\":\\\"shadow\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group shadow\\\"><!-- wp:group {\\\"style\\\":{\\\"spacing\\\":{\\\"padding\\\":{\\\"top\\\":\\\"50px\\\",\\\"right\\\":\\\"2.5em\\\",\\\"bottom\\\":\\\"70px\\\",\\\"left\\\":\\\"2.5em\\\"}},\\\"color\\\":{\\\"background\\\":\\\"#f3faf8\\\"}},\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group has-background\\\" style=\\\"background-color: #f3faf8; padding: 50px 2.5em 70px 2.5em;\\\"><!-- wp:group {\\\"style\\\":{\\\"spacing\\\":{\\\"padding\\\":{\\\"top\\\":\\\"10px\\\",\\\"right\\\":\\\"10px\\\",\\\"bottom\\\":\\\"10px\\\",\\\"left\\\":\\\"10px\\\"}},\\\"border\\\":{\\\"radius\\\":\\\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\\\",\\\"width\\\":\\\"2px\\\"}},\\\"borderColor\\\":\\\"cyan-bluish-gray\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\",\\\"contentSize\\\":\\\"\\\"}} -->\\n<div class=\\\"wp-block-group has-border-color has-cyan-bluish-gray-border-color\\\" style=\\\"border-width: 2px; border-radius: 50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}; padding: 10px;\\\"><!-- wp:image {\\\"id\\\":78,\\\"width\\\":\\\"118px\\\",\\\"height\\\":\\\"auto\\\",\\\"sizeSlug\\\":\\\"full\\\",\\\"linkDestination\\\":\\\"none\\\",\\\"align\\\":\\\"center\\\",\\\"className\\\":\\\"is-style-rounded\\\"} -->\\n<figure class=\\\"wp-block-image aligncenter size-full is-resized is-style-rounded\\\"><img class=\\\"wp-image-78\\\" style=\\\"width: 118px; height: auto;\\\" src=\\\"https:\\/\\/ciac.rw\\/wp-content\\/uploads\\/2024\\/01\\/IMG-1232_JPG.webp\\\" alt=\\\"\\\" \\/><\\/figure>\\n<!-- \\/wp:image --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:group --><!-- wp:group {\\\"style\\\":{\\\"spacing\\\":{\\\"margin\\\":{\\\"top\\\":\\\"0px\\\",\\\"bottom\\\":\\\"0px\\\"},\\\"padding\\\":{\\\"top\\\":\\\"20px\\\",\\\"right\\\":\\\"20px\\\",\\\"bottom\\\":\\\"20px\\\",\\\"left\\\":\\\"20px\\\"}}},\\\"backgroundColor\\\":\\\"white\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group has-white-background-color has-background\\\" style=\\\"margin-top: 0px; margin-bottom: 0px; padding: 20px;\\\"><!-- wp:heading {\\\"textAlign\\\":\\\"center\\\",\\\"level\\\":4,\\\"style\\\":{\\\"typography\\\":{\\\"letterSpacing\\\":\\\"1px\\\"}},\\\"fontSize\\\":\\\"regular\\\"} -->\\n<h4 class=\\\"wp-block-heading has-text-align-center has-regular-font-size\\\" style=\\\"letter-spacing: 1px;\\\">Nduwayezu Leon<\\/h4>\\n<!-- \\/wp:heading --><!-- wp:paragraph {\\\"align\\\":\\\"center\\\",\\\"style\\\":{\\\"spacing\\\":{\\\"margin\\\":{\\\"top\\\":\\\"10px\\\"}}},\\\"textColor\\\":\\\"primary\\\"} -->\\n<p class=\\\"has-text-align-center has-primary-color has-text-color\\\" style=\\\"margin-top: 10px;\\\"><strong><em>BoD member, founder and Disciplinary Committee President<\\/em><\\/strong><\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:details --><details class=\\\"wp-block-details\\\">\\n<summary><strong>E-mail:<\\/strong><br \\/><a href=\\\"mailto:nduluwa@yahoo.fr\\\">nduluwa@yahoo.fr<\\/a><br \\/><strong>Mobile\\/WhatsApp:<\\/strong><br \\/>\\u00a0(250)788300629<br \\/><strong>Languages:\\u00a0<\\/strong><br \\/>English, French, Kinyarwanda<\\/summary>\\n<!-- wp:paragraph {\\\"placeholder\\\":\\\"Type \\/ to add a hidden block\\\"} -->\\n<p>\\u00a0<\\/p>\\n<!-- \\/wp:paragraph --><\\/details><!-- \\/wp:details --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:column --><!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:group {\\\"className\\\":\\\"shadow\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group shadow\\\"><!-- wp:paragraph -->\\n<p>Leon Nduwayezu is an ambitious innovator who aims to resolve Rwanda\\u2019s agricultural packaging problems. Currently, many small holder farmers in Rwanda struggle to deliver safely and securely their fresh produce across the country. With a background in strategic planning and marketing, Leon Nduwayezu has decided to end the packaging problem in Rwandan agro-industry sector by starting AgroPlast Ltd, a company that has been manufacturing net bags since 2015. These bags are used to transport and export mainly potatoes, but also fruits and vegetables are targeted.<\\/p>\\n<!-- \\/wp:paragraph --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:column --><\\/div>\\n<!-- \\/wp:columns --><!-- wp:separator --><hr class=\\\"wp-block-separator has-alpha-channel-opacity\\\" \\/><!-- \\/wp:separator --><!-- wp:columns -->\\n<div class=\\\"wp-block-columns\\\"><!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:group {\\\"className\\\":\\\"shadow\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group shadow\\\"><!-- wp:group {\\\"style\\\":{\\\"spacing\\\":{\\\"padding\\\":{\\\"top\\\":\\\"50px\\\",\\\"right\\\":\\\"2.5em\\\",\\\"bottom\\\":\\\"70px\\\",\\\"left\\\":\\\"2.5em\\\"}},\\\"color\\\":{\\\"background\\\":\\\"#f3faf8\\\"}},\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group has-background\\\" style=\\\"background-color: #f3faf8; padding: 50px 2.5em 70px 2.5em;\\\"><!-- wp:group {\\\"style\\\":{\\\"spacing\\\":{\\\"padding\\\":{\\\"top\\\":\\\"10px\\\",\\\"right\\\":\\\"10px\\\",\\\"bottom\\\":\\\"10px\\\",\\\"left\\\":\\\"10px\\\"}},\\\"border\\\":{\\\"radius\\\":\\\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\\\",\\\"width\\\":\\\"2px\\\"}},\\\"borderColor\\\":\\\"cyan-bluish-gray\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\",\\\"contentSize\\\":\\\"\\\"}} -->\\n<div class=\\\"wp-block-group has-border-color has-cyan-bluish-gray-border-color\\\" style=\\\"border-width: 2px; border-radius: 50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}; padding: 10px;\\\"><!-- wp:image {\\\"id\\\":80,\\\"width\\\":\\\"104px\\\",\\\"height\\\":\\\"auto\\\",\\\"sizeSlug\\\":\\\"full\\\",\\\"linkDestination\\\":\\\"none\\\",\\\"align\\\":\\\"center\\\",\\\"className\\\":\\\"is-style-rounded\\\"} -->\\n<figure class=\\\"wp-block-image aligncenter size-full is-resized is-style-rounded\\\"><img class=\\\"wp-image-80\\\" style=\\\"width: 104px; height: auto;\\\" src=\\\"https:\\/\\/ciac.rw\\/wp-content\\/uploads\\/2024\\/01\\/cia.jpg\\\" alt=\\\"\\\" \\/><\\/figure>\\n<!-- \\/wp:image --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:group --><!-- wp:group {\\\"style\\\":{\\\"spacing\\\":{\\\"margin\\\":{\\\"top\\\":\\\"0px\\\",\\\"bottom\\\":\\\"0px\\\"},\\\"padding\\\":{\\\"top\\\":\\\"20px\\\",\\\"right\\\":\\\"20px\\\",\\\"bottom\\\":\\\"20px\\\",\\\"left\\\":\\\"20px\\\"}}},\\\"backgroundColor\\\":\\\"white\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group has-white-background-color has-background\\\" style=\\\"margin-top: 0px; margin-bottom: 0px; padding: 20px;\\\"><!-- wp:heading {\\\"textAlign\\\":\\\"center\\\",\\\"level\\\":4,\\\"style\\\":{\\\"typography\\\":{\\\"letterSpacing\\\":\\\"1px\\\"}},\\\"fontSize\\\":\\\"regular\\\"} -->\\n<h4 class=\\\"wp-block-heading has-text-align-center has-regular-font-size\\\" style=\\\"letter-spacing: 1px;\\\"><strong>NTIGURA Jean Ferdinand<\\/strong><\\/h4>\\n<!-- \\/wp:heading --><!-- wp:paragraph {\\\"align\\\":\\\"center\\\",\\\"style\\\":{\\\"spacing\\\":{\\\"margin\\\":{\\\"top\\\":\\\"10px\\\"}}},\\\"textColor\\\":\\\"primary\\\"} -->\\n<p class=\\\"has-text-align-center has-primary-color has-text-color\\\" style=\\\"margin-top: 10px;\\\"><strong><em>BoD member, founder and Disciplinary Committee Vice President<\\/em><\\/strong><\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:details {\\\"align\\\":\\\"wide\\\"} --><details class=\\\"wp-block-details alignwide\\\">\\n<summary><strong>Email:<\\/strong><br \\/>jntigura@gmail.com<br \\/><strong>Mobile\\/WhatsApp:<\\/strong><br \\/>+250 783 797 205 (Rw)<strong><br \\/>Skype Name:<\\/strong><br \\/>Ntigura Jean Ferdinand<br \\/><strong>Languages:\\u00a0<\\/strong><br \\/>English, French, Kinyarwanda<\\/summary>\\n<!-- wp:paragraph {\\\"placeholder\\\":\\\"Type \\/ to add a hidden block\\\"} -->\\n<p>\\u00a0<\\/p>\\n<!-- \\/wp:paragraph --><\\/details><!-- \\/wp:details --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:column --><!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:group {\\\"className\\\":\\\"shadow\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group shadow\\\"><!-- wp:paragraph -->\\n<p>Ferdinand holds Bachelor degree in Quantity Surveying and has over 10 years\\u2019 experience in construction industry. Registered, Member of Rwanda Institute of Quantity Surveyor (RIQS), Private and Personnel engaged in business activities. He worked with various construction companies, consultants and developers in Rwanda. He also worked as Civil Servant and holds Local Community responsibilities. Her gained experience and skills help in natural resource management, environmental protection, working with community and construction as well.<\\/p>\\n<!-- \\/wp:paragraph --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:column --><!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:group {\\\"className\\\":\\\"shadow\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group shadow\\\"><!-- wp:group {\\\"style\\\":{\\\"spacing\\\":{\\\"padding\\\":{\\\"top\\\":\\\"50px\\\",\\\"right\\\":\\\"2.5em\\\",\\\"bottom\\\":\\\"70px\\\",\\\"left\\\":\\\"2.5em\\\"}},\\\"color\\\":{\\\"background\\\":\\\"#f3faf8\\\"}},\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group has-background\\\" style=\\\"background-color: #f3faf8; padding: 50px 2.5em 70px 2.5em;\\\"><!-- wp:group {\\\"style\\\":{\\\"spacing\\\":{\\\"padding\\\":{\\\"top\\\":\\\"10px\\\",\\\"right\\\":\\\"10px\\\",\\\"bottom\\\":\\\"10px\\\",\\\"left\\\":\\\"10px\\\"}},\\\"border\\\":{\\\"radius\\\":\\\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\\\",\\\"width\\\":\\\"2px\\\"}},\\\"borderColor\\\":\\\"cyan-bluish-gray\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\",\\\"contentSize\\\":\\\"\\\"}} -->\\n<div class=\\\"wp-block-group has-border-color has-cyan-bluish-gray-border-color\\\" style=\\\"border-width: 2px; border-radius: 50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}; padding: 10px;\\\">\\u00a0<\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:group --><!-- wp:group {\\\"style\\\":{\\\"spacing\\\":{\\\"margin\\\":{\\\"top\\\":\\\"0px\\\",\\\"bottom\\\":\\\"0px\\\"},\\\"padding\\\":{\\\"top\\\":\\\"20px\\\",\\\"right\\\":\\\"20px\\\",\\\"bottom\\\":\\\"20px\\\",\\\"left\\\":\\\"20px\\\"}}},\\\"backgroundColor\\\":\\\"white\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group has-white-background-color has-background\\\" style=\\\"margin-top: 0px; margin-bottom: 0px; padding: 20px;\\\"><!-- wp:paragraph {\\\"align\\\":\\\"center\\\",\\\"style\\\":{\\\"spacing\\\":{\\\"margin\\\":{\\\"top\\\":\\\"10px\\\"}}},\\\"textColor\\\":\\\"primary\\\"} -->\\n<p class=\\\"has-text-align-center has-primary-color has-text-color\\\" style=\\\"margin-top: 10px;\\\">\\u00a0<\\/p>\\n<!-- \\/wp:paragraph --><!-- wp:details --><details class=\\\"wp-block-details\\\">\\n<summary><\\/summary>\\n<!-- wp:paragraph {\\\"placeholder\\\":\\\"Type \\/ to add a hidden block\\\"} -->\\n<p>\\u00a0<\\/p>\\n<!-- \\/wp:paragraph --><\\/details><!-- \\/wp:details --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:column --><!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:group {\\\"className\\\":\\\"shadow\\\",\\\"layout\\\":{\\\"type\\\":\\\"constrained\\\"}} -->\\n<div class=\\\"wp-block-group shadow\\\"><!-- wp:paragraph -->\\n<p>\\u00a0<\\/p>\\n<!-- \\/wp:paragraph --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:column --><\\/div>\\n<!-- \\/wp:columns --><\\/div>\\n<!-- \\/wp:group --><\\/div>\\n<!-- \\/wp:group -->\",\"column_gap\":{\"unit\":\"px\",\"size\":0,\"sizes\":[]}},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false},{\"id\":\"81303f4\",\"elType\":\"container\",\"settings\":{\"container_type\":\"grid\",\"grid_columns_grid\":{\"unit\":\"fr\",\"size\":\"2\"},\"grid_rows_grid\":{\"unit\":\"fr\",\"size\":\"1\"},\"grid_rows_grid_mobile\":{\"unit\":\"fr\",\"size\":\"1\"}},\"elements\":[],\"isInner\":false}]");
