le=\"margin-top:0px;font-style:normal;font-weight:700\">Building a Sustainable Future: Efficient Resources, Environmentally Friendly Agriculture</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"lineHeight\":\"1.6\"}},\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\" style=\"line-height:1.6\">CIAC (Centre intervention et d’Action Communautaire) is a National NGO: a non-profit making, non-governmental organization with its head office in Kigali city (Kicukiro District. It operates in all provinces of Rwanda. CIAC was established in June 2022.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"backgroundColor\":\"white\",\"textColor\":\"secondary\",\"style\":{\"typography\":{\"letterSpacing\":\"2px\"}}} -->\n<div class=\"wp-block-button\" style=\"letter-spacing:2px\"><a class=\"wp-block-button__link has-secondary-color has-white-background-color has-text-color has-background wp-element-button\">Learn More</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div></div>\n<!-- /wp:cover --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"main\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"}}},\"layout\":{\"type\":\"default\"}} -->\n<main class=\"wp-block-group\" style=\"margin-top:0px;margin-bottom:0px\"><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"60px\",\"right\":\"20px\",\"bottom\":\"60px\",\"left\":\"20px\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group\" style=\"margin-top:0px;margin-bottom:0px;padding-top:60px;padding-right:20px;padding-bottom:60px;padding-left:20px\"><!-- wp:group {\"align\":\"wide\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignwide\"><!-- wp:group {\"align\":\"wide\",\"className\":\"section_head\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignwide section_head\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"}},\"className\":\"section_sub_title\",\"fontSize\":\"body-text\",\"fontFamily\":\"catamaran\"} -->\n<h4 class=\"wp-block-heading has-text-align-center section_sub_title has-catamaran-font-family has-body-text-font-size\" style=\"font-style:normal;font-weight:500\"><strong>CIAC’s intervention domains</strong>:</h4>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\",\"fontSize\":\"40px\"},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\",\"className\":\"section_title\"} -->\n<h2 class=\"wp-block-heading has-text-align-center section_title has-primary-color has-text-color has-link-color\" style=\"margin-top:0px;font-size:40px;font-style:normal;font-weight:700\">Promoting Environmental Friendly Practices</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">CIAC has been established in January 2022 with the overall goal of contributing to the promotion of Rwandan communities by improving livelihood through efficient use of natural resources and promoting environmentally friendly agriculture for sustainable development.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:spacer {\"height\":\"10px\"} -->\n<div style=\"height:10px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:group -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px