INSERT INTO `oJegmj1Sz_posts` VALUES("31","1","2024-01-16 14:24:39","2024-01-16 14:24:39","<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\"} -->\n<p class=\"has-text-align-center has-primary-color has-text-color has-link-color\"><strong><em>Reach us via:</em></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\"><strong>E-mail: info@ciac.rw</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\"><strong>Tel: <a href=\"http://+250785507355\">+250785507355</a></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\"} -->\n<p class=\"has-text-align-center has-primary-color has-text-color has-link-color\"><strong>Head Office:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\"><strong>Kigali-Rwanda</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\"><strong>Kicukiro District</strong></p>\n<!-- /wp:paragraph -->","Contact us","","publish","closed","closed","","home","","","2025-10-09 08:15:00","2025-10-09 08:15:00","","0","https://ciac.rw/?page_id=31","0","page","","0");
INSERT INTO `oJegmj1Sz_posts` VALUES("32","1","2024-01-16 14:24:39","2024-01-16 14:24:39","","Home","","inherit","closed","closed","","31-revision-v1","","","2024-01-16 14:24:39","2024-01-16 14:24:39","","31","https://ciac.rw/?p=32","0","revision","","0");
INSERT INTO `oJegmj1Sz_posts` VALUES("33","1","2024-01-16 14:26:03","2024-01-16 14:26:03","<!-- wp:paragraph -->\n<p><strong>who are we</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>CIAC is a local NGO legally registered in Rwanda. It started operating in 2021 with an operational certificate and obtained legal personality in 2024.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Mission:</strong> </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Our mission is to enhance the livelihoods of Rwandan farmers by promoting agroecological practices through the implementation of integrated farm plans at the family level.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Vision:</strong> </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Our Vision is to be a leader in agroecology, especially in agroforestry, across Africa.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Our Approach:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We promote working on farm plans at the family level.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p> <strong>Farmers\' Family Plan: A plan of 3 to 5 years including:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>The plan should be developed collaboratively, in inclusive workshops that build understanding and buy-in from all family members, especially spouses</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>SWOT analysis at both family and farm levels</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>A vision of what the family needs to look like within the defined timeframe</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>The reasons and mission behind the family\'s intentions</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>How the family will achieve these goals</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Everyone’s individual roles and responsibilities</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Objectives of the Organization</strong>:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Fight against violence in families by leading group discussions with the aim of analysing and providing adequate solutions</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Install in the population the culture of working in their family plans based on a schedule based on the National strategies plan of the&nbsp;&nbsp; country</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Protect natural resources and promote agricultural techniques which are environmentally friendly.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Promote hygiene and sanitation through the development and management of water and sanitation infrastructures and increase the number of accesses to clean water and sanitation facilities.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Promote gender equality between men and women, I.C.T and entrepreneurship by women and youth based to&nbsp;&nbsp; speed&nbsp;&nbsp;&nbsp; up sustainable development&nbsp;&nbsp;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Promote research and education based on philosophy and culture for knowing poverty causes and eradication strategies.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>To promote child rights, Education, child labor, etc…</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>To promote humanitarian actions from vulnerability to disasters, war or epidemics.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->","About Us","","publish","closed","closed","","about-us","","","2024-07-19 16:07:12","2024-07-19 16:07:12","","0","https://ciac.rw/?page_id=33","0","page","","0");
INSERT INTO `oJegmj1Sz_posts` VALUES("34","1","2024-01-16 14:26:03","2024-01-16 14:26:03","<!-- wp:paragraph -->\n<p>CIAC (Centre intervention et d’Action Communautaire) is a National NGO: a non-profit making, non-governmental organization with its head office in Kigali city (Kicukiro District. It operates in all provinces of Rwanda. CIAC was established in June 2022.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Mission:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>CIAC’s mission is to contribute to the socio-economic development of Rwandan communities by improving livelihood through efficient use of natural resources and promoting environmentally friendly agriculture for sustainable development.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Objectives of the Organization</strong>:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>Fight against violence in families by leading group discussions with the aim of analysing and providing adequate solutions</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Install in the population the culture of working in their family plans based on a schedule based on the National strategies plan of the&nbsp;&nbsp; country</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Protect natural resources and promote agricultural techniques which are environmentally friendly.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Promote hygiene and sanitation through the development and management of water and sanitation infrastructures and increase the number of accesses to clean water and sanitation facilities.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Promote gender equality between men and women, I.C.T and entrepreneurship by women and youth based to&nbsp;&nbsp; speed&nbsp;&nbsp;&nbsp; up sustainable development&nbsp;&nbsp;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Promote research and education based on philosophy and culture for knowing poverty causes and eradication strategies.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>To promote child rights, Education, child labor, etc…</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>To promote humanitarian actions from vulnerability to disasters, war or epidemics.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->","About Us","","inherit","closed","closed","","33-revision-v1","","","2024-01-16 14:26:03","2024-01-16 14:26:03","","33","https://ciac.rw/?p=34","0","revision","","0");
