ttp://gov.rw\" data-type=\"link\" data-id=\"gov.rw\"><strong>Government Website</strong></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"spacing\":{\"margin\":{\"top\":\"15px\"}},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\"} -->\n<p class=\"has-primary-color has-text-color has-link-color\" style=\"margin-top:15px\"><strong><a href=\"http://www.environment.gov.rw\">Ministry of Environment</a></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"spacing\":{\"margin\":{\"top\":\"15px\"}},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\"} -->\n<p class=\"has-primary-color has-text-color has-link-color\" style=\"margin-top:15px\"><strong><a href=\"http://www.minagri.gov.rw\">Ministry of Agriculture</a></strong></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"top\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top\"><!-- wp:heading {\"textAlign\":\"left\",\"fontSize\":\"regular\"} -->\n<h2 class=\"wp-block-heading has-text-align-left has-regular-font-size\">Key Partners</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"className\":\"is-style-wide\",\"backgroundColor\":\"primary\"} -->\n<hr class=\"wp-block-separator has-text-color has-primary-color has-alpha-channel-opacity has-primary-background-color has-background is-style-wide\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph -->\n<p>Wageningen ndiza Foundation</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"spacing\":{\"margin\":{\"top\":\"15px\"}}}} -->\n<p style=\"margin-top:15px\"><a href=\"https://www.dibcoop.nl/\" data-type=\"link\" data-id=\"https://www.dibcoop.nl/\">DIBcoop</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"spacing\":{\"margin\":{\"top\":\"15px\"}},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\"} -->\n<p class=\"has-primary-color has-text-color has-link-color\" style=\"margin-top:15px\"><a href=\"https://agroplastrwanda.org/\" data-type=\"link\" data-id=\"https://agroplastrwanda.org/\">AgroPlast Ltd</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"spacing\":{\"margin\":{\"top\":\"15px\"}},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\"} -->\n<p class=\"has-primary-color has-text-color has-link-color\" style=\"margin-top:15px\"><a href=\"https://ifssgoal.org/our-services/\" data-type=\"link\" data-id=\"https://ifssgoal.org/our-services/\">IFFS International</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"level\":4,\"fontSize\":\"regular\"} -->\n<h4 class=\"wp-block-heading has-regular-font-size\">Gallery</h4>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"className\":\"is-style-wide\",\"backgroundColor\":\"primary\"} -->\n<hr class=\"wp-block-separator has-text-color has-primary-color has-alpha-channel-opacity has-primary-background-color has-background is-style-wide\"/>\n<!-- /wp:separator -->\n\n<!-- wp:gallery {\"columns\":3,\"linkTo\":\"none\",\"style\":{\"spacing\":{\"blockGap\":{\"top\":\"var:preset|spacing|20\",\"left\":\"var:preset|spacing|20\"}}}} -->\n<figure class=\"wp-block-gallery has-nested-images columns-3 is-cropped\"><!-- wp:image {\"id\":53,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"https://ciac.rw/wp-content/uploads/2024/01/WhatsApp-Image-2024-01-16-at-12.12.20-PM-1-1024x768.jpeg\" alt=\"\" class=\"wp-image-53\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":54,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"https://ciac.rw/wp-content/uploads/20