ing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#f3faf8;padding-top:50px;padding-right:2.5em;padding-bottom:70px;padding-left:2.5em\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<div class=\"wp-block-group has-border-color has-cyan-bluish-gray-border-color\" style=\"border-width:2px;border-radius:50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb};padding-top:10px;padding-right:10px;padding-bottom:10px;padding-left:10px\"><!-- wp:image {\"align\":\"center\",\"id\":75,\"width\":\"104px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-full is-resized is-style-rounded\"><img src=\"https://ciac.rw/wp-content/uploads/2024/01/Drocella.png\" alt=\"\" class=\"wp-image-75\" style=\"width:104px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"margin-top:0px;margin-bottom:0px;padding-top:20px;padding-right:20px;padding-bottom:20px;padding-left:20px\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 class=\"wp-block-heading has-text-align-center has-regular-font-size\" style=\"letter-spacing:1px\"><strong>Drocelle Musabyimana</strong></h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p class=\"has-text-align-center has-primary-color has-text-color\" style=\"margin-top:10px\"><strong><em>President of the BoD , founder and Legal Representative</em></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:details {\"align\":\"wide\"} -->\n<details class=\"wp-block-details alignwide\"><summary><strong>Email:</strong><br>mudrocelle@gmail.com<br><strong>Mobile/WhatsApp:</strong><br>+250 785 507 355 (Rw)<strong><br>Skype Name:</strong><br>Drocelle Musabyimana<br><strong>Languages: </strong><br>English, French, Kinyarwanda</summary><!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p></p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group shadow\"><!-- wp:paragraph -->\n<p>Drocelle is a Water and Environmental Engineer and Master’s student in Environmental Science ahead to completion. She uses her skills to contribute to the sustainable development of Africa, combining them with her interest in small farmer empowerment, wealth equality and financial inclusion. She believes that small farmers in Africa are the key to achieving sustainable development, for which a bottom-up approach is crucial. She is currently works with DIBcoop, an International Business development as Director Rwanda Office and she has previous worked with SHER-Rwanda, MDF among other where she gained experience in natural resource management, environmental protection, working with farmers and in construction. She contributes to the DIBcoop team in Rwanda by supporting community engagement processes, developing and implementing integrated water catchment plans, and assisting with M&amp;E reporting.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group shadow\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#f3faf8;padding-top:50px;padding-right:2.5em;padding-bottom:70px;padding-left:2.5em\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<div class=\"wp-block-group has-border-color has-cyan-bluish-gray-border-color\" style=\"border-width:2px;border-radius:50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb};padding-top:10px;padding-right:10px;padding-bottom:10px;padding-left:10px\"><!-- wp:image {\"align\":\"center\",\"id\":78,\"width\":\"118px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-full is-resized is-style-rounded\"><img src=\"https://ciac.rw/wp-content/uploads/2024/01/IMG-1232_JPG.webp\" alt=\"\" class=\"wp-image-78\" style=\"width:118px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"margin-top:0px;margin-bottom:0px;padding-top:20px;padding-right:20px;padding-bottom:20px;padding-left:20px\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 class=\"wp-block-heading has-text-align-center has-regular-font-size\" style=\"letter-spacing:1px\">Nduwayezu Leon</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p class=\"has-text-align-center has-primary-color has-text-color\" style=\"margin-top:10px\"><strong><em>BoD member, founder and Disciplinary Committee President</em></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary><strong>E-mail:</strong><br><a href=\"mailto:nduluwa@yahoo.fr\">nduluwa@yahoo.fr</a><br><strong>Mobile/WhatsApp:</strong><br> (250)788300629<br><strong>Languages: </strong><br>English, French, Kinyarwanda</summary><!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p></p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group shadow\"><!-- wp:paragraph -->\n<p>Leon Nduwayezu is an ambitious innovator who aims to resolve Rwanda’s agricultural packaging problems. Currently, many small holder farmers in Rwanda struggle to deliver safely and securely their fresh produce across the country. With a background in strategic planning and marketing, Leon Nduwayezu has decided to end the packaging problem in Rwandan agro-industry sector by starting AgroPlast Ltd, a company that has been manufacturing net bags since 2015. These bags are used to transport and export mainly potatoes, but also fruits and vegetables are targeted.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group shadow\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#f3faf8;padding-top:50px;padding-right:2.5em;padding-bottom:70px;padding-left:2.5em\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<div class=\"wp-block-group has-border-color has-cyan-bluish-gray-border-color\" style=\"border-width:2px;border-radius:50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb};padding-top:10px;padding-right:10px;padding-bottom:10px;padding-left:10px\"><!-- wp:image {\"align\":\"center\",\"id\":80,\"width\":\"104px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-full is-resized is-style-rounded\"><img src=\"https://ciac.rw/wp-content/uploads/2024/01/cia.jpg\" alt=\"\" class=\"wp-image-80\" style=\"width:104px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"margin-top:0px;margin-bottom:0px;padding-top:20px;padding-right:20px;padding-bottom:20px;padding-left:20px\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 class=\"wp-block-heading has-text-align-center has-regular-font-size\" style=\"letter-spacing:1px\"><strong>NTIGURA Jean Ferdinand</strong></h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p class=\"has-text-align-center has-primary-color has-text-color\" style=\"margin-top:10px\"><strong><em>BoD member, founder and Disciplinary Committee Vice President</em></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:details {\"align\":\"wide\"} -->\n<details class=\"wp-block-details alignwide\"><summary><strong>Email:</strong><br>jntigura@gmail.com<br><strong>Mobile/WhatsApp:</strong><br>+250 783 797 205 (Rw)<strong><br>Skype Name:</strong><br>Ntigura Jean Ferdinand<br><strong>Languages: </strong><br>English, French, Kinyarwanda</summary><!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p></p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group shadow\"><!-- wp:paragraph -->\n<p>Ferdinand holds Bachelor degree in Quantity Surveying and has over 10 years’ experience in construction industry. Registered, Member of Rwanda Institute of Quantity Surveyor (RIQS), Private and Personnel engaged in business activities. He worked with various construction companies, consultants and developers in Rwanda. He also worked as Civil Servant and holds Local Community responsibilities. Her gained experience and skills help in natural resource management, environmental protection, working with community and construction as well.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group shadow\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#f3faf8;padding-top:50px;padding-right:2.5em;padding-bottom:70px;padding-left:2.5em\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<div class=\"wp-block-group has-border-color has-cyan-bluish-gray-border-color\" style=\"border-width:2px;border-radius:50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb};padding-top:10px;padding-right:10px;padding-bottom:10px;padding-left:10px\"><!-- wp:image {\"align\":\"center\",\"id\":78,\"width\":\"118px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image aligncenter size-full is-resized is-style-rounded\"><img src=\"https://ciac.rw/wp-content/uploads/2024/01/IMG-1232_JPG.webp\" alt=\"\" class=\"wp-image-78\" style=\"width:118px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"margin-top:0px;margin-bottom:0px;padding-top:20px;padding-right:20px;padding-bottom:20px;padding-left:20px\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 class=\"wp-block-heading has-text-align-center has-regular-font-size\" style=\"letter-spacing:1px\">Nduwayezu Leon</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p class=\"has-text-align-center has-primary-color has-text-color\" style=\"margin-top:10px\"><strong><em>BoD member, founder and Disciplinary Committee President</em></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary><strong>E-mail:</strong><br><a href=\"mailto:nduluwa@yahoo.fr\">nduluwa@yahoo.fr</a><br><strong>Mobile/WhatsApp:</strong><br> (250)788300629<br><strong>Languages: </strong><br>English, French, Kinyarwanda</summary><!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p></p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group shadow\"><!-- wp:paragraph -->\n<p>Leon Nduwayezu is an ambitious innovator who aims to resolve Rwanda’s agricultural packaging problems. Currently, many small holder farmers in Rwanda struggle to deliver safely and securely their fresh produce across the country. With a background in strategic planning and marketing, Leon Nduwayezu has decided to end the packaging problem in Rwandan agro-industry sector by starting AgroPlast Ltd, a company that has been manufacturing net bags since 2015. These bags are used to transport and export mainly potatoes, but also fruits and vegetables are targeted.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->","Our Team","","inherit","closed","closed","","72-revision-v1","","","2024-01-19 11:32:29","2024-01-19 11:32:29","","72","https://ciac.rw/?p=88","0","revision","","0");
