-heading has-text-align-center section_sub_title has-catamaran-font-family has-body-text-font-size\" style=\"font-style:normal;font-weight:500\">Blogs &amp; News</h4>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\",\"fontSize\":\"40px\"}},\"className\":\"section_title\"} -->\n<h2 class=\"wp-block-heading has-text-align-center section_title\" style=\"margin-top:0px;font-size:40px;font-style:normal;font-weight:700\">Latest News &amp; Updates</h2>\n<!-- /wp:heading -->\n\n<!-- wp:spacer {\"height\":\"10px\"} -->\n<div style=\"height:10px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:group -->\n\n<!-- wp:query {\"queryId\":3,\"query\":{\"perPage\":3,\"pages\":\"1\",\"offset\":0,\"postType\":\"post\",\"order\":\"desc\",\"orderBy\":\"date\",\"author\":\"\",\"search\":\"\",\"exclude\":[],\"sticky\":\"\",\"inherit\":false}} -->\n<div class=\"wp-block-query\"><!-- wp:post-template {\"className\":\"m-0 list-none\",\"layout\":{\"type\":\"grid\",\"columnCount\":3}} -->\n<!-- wp:group {\"className\":\"news-box\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group news-box\"><!-- wp:group {\"className\":\"news-thumb\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group news-thumb\"><!-- wp:post-featured-image {\"className\":\"news-thumb-wrap\"} /--></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"news-content\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group news-content\"><!-- wp:post-terms {\"term\":\"category\",\"fontSize\":\"small\"} /-->\n\n<!-- wp:post-title {\"level\":3,\"isLink\":true,\"style\":{\"typography\":{\"fontSize\":\"30px\",\"fontStyle\":\"normal\",\"fontWeight\":\"600\",\"lineHeight\":\"1.2\"},\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"10px\"}}}} /-->\n\n<!-- wp:group {\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"space-between\"}} -->\n<div class=\"wp-block-group\"><!-- wp:post-author-name {\"isLink\":true} /-->\n\n<!-- wp:paragraph -->\n<p><a href=\"#\">2 Comments</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:post-excerpt {\"moreText\":\"\",\"showMoreOnNewLine\":false} /-->\n\n<!-- wp:group {\"layout\":{\"type\":\"constrained\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-group\"><!-- wp:read-more {\"content\":\"Read More\",\"style\":{\"spacing\":{\"padding\":{\"right\":\"5px\",\"bottom\":\"5px\",\"left\":\"5px\"}},\"border\":{\"bottom\":{\"color\":\"var:preset|color|primary\",\"width\":\"2px\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\"}},\"textColor\":\"primary\"} /--></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n<!-- /wp:post-template -->\n\n<!-- wp:query-no-results -->\n<!-- wp:paragraph {\"placeholder\":\"Add text or blocks that will display when a query returns no results.\"} -->\n<p>There is no post found</p>\n<!-- /wp:paragraph -->\n<!-- /wp:query-no-results --></div>\n<!-- /wp:query --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></main>\n<!-- /wp:group -->\n\n<!-- wp:template-part {\"slug\":\"footer\",\"theme\":\"greengrass\",\"tagName\":\"footer\"} /-->","Blog Home","Displays the latest posts as either the site homepage or as the \"Posts page\" as defined under reading settings. If it exists, the Front Page template overrides this template when posts are shown on the homepage.","inherit","closed","closed","","15-revision-v1","","","2024-01-19 12:26:45","2024-01-19 12:26:45","","15","https://ciac.rw/?p=92","0","revision","","0");
INSERT INTO `oJegmj1Sz_posts` VALUES("93","1","2024-01-19 12:28:32","2024-01-19 12:28:32","<!-- wp:template-part {\"slug\":\"header\",\"theme\":\"greengrass\",\"tagName\":\"header\"} /-->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\"}}}} -->\n<div class=\"wp-block-group\" style=\"margin-top:0px\"><!-- wp:cover {\"url\":\"https://ciac.rw/wp-content/uploads/2024/01/53299587626_c3909a21ca_k.jpg\",\"id\":9,\"hasParallax\":true,\"isRepeated\":true,\"dimRatio\":40,\"overlayColor\":\"vivid-green-cyan\",\"minHeight\":800,\"isDark\":false,\"align\":\"full\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}}} -->\n<div class=\"wp-block-cover alignfull is-light has-parallax is-repeated\" style=\"padding-top:20px;padding-right:20px;padding-bottom:20px;padding-left:20px;min-height:800px\"><span aria-hidden=\"true\" class=\"wp-block-cover__background has-vivid-green-cyan-background-color has-background-dim-40 has-background-dim\"></span><div role=\"img\" class=\"wp-block-cover__image-background wp-image-9 has-parallax is-repeated\" style=\"background-position:50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb} 50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb};background-image:url(https://ciac.rw/wp-content/uploads/2024/01/53299587626_c3909a21ca_k.jpg)\"></div><div class=\"wp-block-cover__inner-container\"><!-- wp:group {\"align\":\"wide\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignwide\"><!-- wp:group {\"align\":\"wide\",\"className\":\"nivo-caption\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignwide nivo-caption\"><!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"style\":{\"color\":{\"background\":\"#019443d6\"},\"spacing\":{\"padding\":{\"top\":\"3em\",\"right\":\"3em\",\"bottom\":\"3em\",\"left\":\"3em\"}}}} -->\n<div class=\"wp-block-column has-background\" style=\"background-color:#019443d6;padding-top:3em;padding-right:3em;padding-bottom:3em;padding-left:3em\"><!-- wp:heading {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\"},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|white\"}}}},\"textColor\":\"white\",\"fontSize\":\"regular\",\"fontFamily\":\"satisfy\"} -->\n<h2 class=\"wp-block-heading has-white-color has-text-color has-link-color has-satisfy-font-family has-regular-font-size\" style=\"margin-top:0px;font-style:normal;font-weight:700\">Building a Sustainable Future: Efficient Resources, Environmentally Friendly Agriculture</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"lineHeight\":\"1.6\"}},\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\" style=\"line-height:1.6\"><strong>CIAC (Centre intervention et d’Action Communautaire) is a National NGO: a non-profit making, non-governmental organization with its head office in Kigali city (Kicukiro District. It operates in all provinces of Rwanda. CIAC was established in June 2022.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"backgroundColor\":\"white\",\"textColor\":\"secondary\",\"style\":{\"typography\":{\"letterSpacing\":\"2px\",\"fontSize\":\"22px\"},\"spacing\":{\"padding\":{\"left\":\"0\",\"right\":\"0\"}}},\"className\":\"is-style-outline\"} -->\n<div class=\"wp-block-button has-custom-font-size is-style-outline\" style=\"font-size:22px;letter-spacing:2px\"><a class=\"wp-block-button__link has-secondary-color has-white-background-color has-text-color has-background wp-element-button\" href=\"https://ciac.rw/?page_id=50\" style=\"padding-right:0;padding-left:0\"><strong>Learn More</strong></a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:search {\"label\":\"\\u003cstrong\\u003eSearch our site\\u003c/strong\\u003e\",\"width\":100,\"widthUnit\":\"{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"buttonText\":\"Search\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|white\"}}}},\"backgroundColor\":\"primary\",\"textColor\":\"white\",\"fontSize\":\"medium\"} /--></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div></div>\n<!-- /wp:cover --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"main\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"}}},\"layout\":{\"type\":\"default\"}} -->\n<main class=\"wp-block-group\" style=\"margin-top:0px;margin-bottom:0px\"><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"60px\",\"right\":\"20px\",\"bottom\":\"60px\",\"left\":\"20px\"}},\"color\":{\"background\":\"#080834\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#080834;margin-top:0px;margin-bottom:0px;padding-top:60px;padding-right:20px;padding-bottom:60px;padding-left:20px\"><!-- wp:group {\"align\":\"wide\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignwide\"><!-- wp:group {\"align\":\"wide\",\"className\":\"section_head\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignwide section_head\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|white\"}}}},\"textColor\":\"white\",\"className\":\"section_sub_title\",\"fontSize\":\"body-text\",\"fontFamily\":\"catamaran\"} -->\n<h4 class=\"wp-block-heading has-text-align-center section_sub_title has-white-color has-text-color has-link-color has-catamaran-font-family has-body-text-font-size\" style=\"font-style:normal;font-weight:500\"><strong>CIAC’s intervention domains:</strong></h4>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\",\"fontSize\":\"40px\"},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\",\"className\":\"section_title\"} -->\n<h2 class=\"wp-block-heading has-text-align-center section_title has-primary-color has-text-color has-link-color\" style=\"margin-top:0px;font-size:40px;font-style:normal;font-weight:700\">Promoting Environmental Friendly Practices</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|section-bg\"}}}},\"textColor\":\"section-bg\"} -->\n<p class=\"has-text-align-center has-section-bg-color has-text-color has-link-color\">CIAC has been established in January 2022 with the overall goal of contributing to the promotion of Rwandan communities by improving livelihood through efficient use of natural resources and promoting environmentally friendly agriculture for sustainable development.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:spacer {\"height\":\"10px\"} -->\n<div style=\"height:10px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:group -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}},\"border\":{\"radius\":\"12px\"}},\"backgroundColor\":\"white\",\"className\":\"service-box\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group service-box has-white-background-color has-background\" style=\"border-radius:12px;padding-top:20px;padding-right:20px;padding-bottom:20px;padding-left:20px\"><!-- wp:group {\"className\":\"service-box-thumb\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group service-box-thumb\"><!-- wp:image {\"align\":\"center\",\"id\":21,\"width\":\"240px\",\"height\":\"160px\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image aligncenter size-full is-resized\"><img src=\"https://ciac.rw/wp-content/uploads/2024/01/52954768134_5fb955386c_3k.jpg\" alt=\"\" class=\"wp-image-21\" style=\"object-fit:cover;width:240px;height:160px\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"bottom\":\"0px\",\"top\":\"0px\"}}},\"className\":\"service-box-content\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group service-box-content\" style=\"margin-top:0px;margin-bottom:0px\"><!-- wp:group {\"className\":\"service-box-icon\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group service-box-icon\"><!-- wp:image {\"align\":\"center\",\"id\":635,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image aligncenter size-full\"><img src=\"https://ciac.rw/wp-content/themes/greengrass/images/ser-icon1.png\" alt=\"\" class=\"wp-image-635\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\"} -->\n<h3 class=\"wp-block-heading has-text-align-center has-primary-color has-text-color has-link-color\">Environment management.</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">This activity includes activities such as assessing and mitigating environmental risks, implementing waste management strategies, conserving natural resources, promoting renewable energy sources, and adhering to environmental regulations.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"}}},\"className\":\"service-number\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group service-number\" style=\"margin-top:0px;margin-bottom:0px\"><!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}},\"border\":{\"radius\":\"12px\"}},\"backgroundColor\":\"white\",\"className\":\"service-box\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group service-box has-white-background-color has-background\" style=\"border-radius:12px;padding-top:20px;padding-right:20px;padding-bottom:20px;padding-left:20px\"><!-- wp:group {\"className\":\"service-box-thumb\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group service-box-thumb\"><!-- wp:image {\"align\":\"center\",\"id\":22,\"width\":\"240px\",\"height\":\"160px\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image aligncenter size-full is-resized\"><img src=\"https://ciac.rw/wp-content/uploads/2024/01/53390679189_63fb7c45cd_5k.jpg\" alt=\"\" class=\"wp-image-22\" style=\"object-fit:cover;width:240px;height:160px\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"}}},\"className\":\"service-box-content\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group service-box-content\" style=\"margin-top:0px;margin-bottom:0px\"><!-- wp:group {\"className\":\"service-box-icon\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group service-box-icon\"><!-- wp:image {\"align\":\"center\",\"id\":662,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image aligncenter size-full\"><img src=\"https://ciac.rw/wp-content/themes/greengrass/images/ser-icon2.png\" alt=\"\" class=\"wp-image-662\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}}},\"textColor\":\"primary\"} -->\n<h3 class=\"wp-block-heading has-text-align-center has-primary-color has-text-color has-link-color\">Climate change adaptation and mitigation</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">We work towards developing strategies and implementing measures that help societies and ecosystems adapt to the changing climate conditions while also working towards reducing the causes of climate change.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"}}},\"className\":\"service-number\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group service-number\" style=\"margin-top:0px;margin-bottom:0px\"><!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}},\"border\":{\"radius\":\"12px\"}},\"backgroundColor\":\"white\",\"className\":\"service-box\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group service-box has-white-background-color has-background\" style=\"border-radius:12px;padding-top:20px;padding-right:20px;padding-bottom:20px;padding-left:20px\"><!-- wp:group {\"className\":\"service-box-thumb\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group service-box-thumb\"><!-- wp:image {\"align\":\"center\",\"id\":23,\"width\":\"240px\",\"height\":\"160px\",\"scal