p:post-author-name {\"isLink\":true} /-->\n\n<!-- wp:paragraph -->\n<p><a href=\"#\">2 Comments</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:post-excerpt {\"moreText\":\"\",\"showMoreOnNewLine\":false} /-->\n\n<!-- wp:group {\"layout\":{\"type\":\"constrained\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-group\"><!-- wp:read-more {\"content\":\"Read More\",\"style\":{\"spacing\":{\"padding\":{\"right\":\"5px\",\"bottom\":\"5px\",\"left\":\"5px\"}},\"border\":{\"bottom\":{\"color\":\"var:preset|color|primary\",\"width\":\"2px\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\"}},\"textColor\":\"primary\"} /--></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n<!-- /wp:post-template -->\n\n<!-- wp:query-no-results -->\n<!-- wp:paragraph {\"placeholder\":\"Add text or blocks that will display when a query returns no results.\"} -->\n<p>There is no post found</p>\n<!-- /wp:paragraph -->\n<!-- /wp:query-no-results --></div>\n<!-- /wp:query --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></main>\n<!-- /wp:group -->\n\n<!-- wp:template-part {\"slug\":\"footer\",\"theme\":\"greengrass\",\"tagName\":\"footer\"} /-->","Blog Home","Displays the latest posts as either the site homepage or as the \"Posts page\" as defined under reading settings. If it exists, the Front Page template overrides this template when posts are shown on the homepage.","inherit","closed","closed","","15-revision-v1","","","2024-04-03 16:52:14","2024-04-03 16:52:14","","15","https://ciac.rw/?p=107","0","revision","","0");
