INSERT INTO `oJegmj1Sz_posts` VALUES("152","1","2025-10-28 08:46:20","2025-10-28 08:46:20","<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"60px\",\"right\":\"20px\",\"bottom\":\"60px\",\"left\":\"20px\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"align\":\"wide\",\"layout\":{\"type\":\"default\"}} -->\n<!-- wp:group {\"align\":\"wide\",\"className\":\"section_head\",\"layout\":{\"type\":\"default\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"}},\"className\":\"section_sub_title\",\"fontSize\":\"body-text\",\"fontFamily\":\"catamaran\"} -->\n<h4 style=\"font-style: normal; font-weight: 500;\">Our Team</h4>\n<!-- /wp:heading --><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\",\"fontSize\":\"40px\"}},\"className\":\"section_title\"} -->\n<h2 style=\"margin-top: 0px; font-size: 40px; font-style: normal; font-weight: bold;\">CIAC Experts</h2>\n<!-- /wp:heading --><!-- wp:spacer {\"height\":\"10px\"} -->\n \n<!-- /wp:spacer -->\n<!-- /wp:group --><!-- wp:columns -->\n<!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<!-- wp:image {\"id\":75,\"width\":\"104px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure><img style=\"width: 104px; height: auto;\" src=\"https://ciac.rw/wp-content/uploads/2024/01/Drocella.png\" alt=\"\" /></figure>\n<!-- /wp:image -->\n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 style=\"letter-spacing: 1px;\"><strong>Drocelle Musabyimana</strong></h4>\n<!-- /wp:heading --><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"><strong><em>President of the BoD , founder and Legal Representative</em></strong></p>\n<!-- /wp:paragraph --><!-- wp:details {\"align\":\"wide\"} --><details>\n<summary><strong>Email:</strong><br />mudrocelle@gmail.com<br /><strong>Mobile/WhatsApp:</strong><br />+250 785 507 355 (Rw)<strong><br />Skype Name:</strong><br />Drocelle Musabyimana<br /><strong>Languages: </strong><br />English, French, Kinyarwanda</summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p>Drocelle is a Water and Environmental Engineer and Master’s student in Environmental Science ahead to completion. She uses her skills to contribute to the sustainable development of Africa, combining them with her interest in small farmer empowerment, wealth equality and financial inclusion. She believes that small farmers in Africa are the key to achieving sustainable development, for which a bottom-up approach is crucial. She is currently works with DIBcoop, an International Business development as Director Rwanda Office and she has previous worked with SHER-Rwanda, MDF among other where she gained experience in natural resource management, environmental protection, working with farmers and in construction. She contributes to the DIBcoop team in Rwanda by supporting community engagement processes, developing and implementing integrated water catchment plans, and assisting with M&amp;E reporting.</p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<!-- wp:image {\"id\":78,\"width\":\"118px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure><img style=\"width: 118px; height: auto;\" src=\"https://ciac.rw/wp-content/uploads/2024/01/IMG-1232_JPG.webp\" alt=\"\" /></figure>\n<!-- /wp:image -->\n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 style=\"letter-spacing: 1px;\">Nduwayezu Leon</h4>\n<!-- /wp:heading --><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"><strong><em>BoD member, founder and Disciplinary Committee President</em></strong></p>\n<!-- /wp:paragraph --><!-- wp:details --><details>\n<summary><strong>E-mail:</strong><br /><a href=\"mailto:nduluwa@yahoo.fr\">nduluwa@yahoo.fr</a><br /><strong>Mobile/WhatsApp:</strong><br /> (250)788300629<br /><strong>Languages: </strong><br />English, French, Kinyarwanda</summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p>Leon Nduwayezu is an ambitious innovator who aims to resolve Rwanda’s agricultural packaging problems. Currently, many small holder farmers in Rwanda struggle to deliver safely and securely their fresh produce across the country. With a background in strategic planning and marketing, Leon Nduwayezu has decided to end the packaging problem in Rwandan agro-industry sector by starting AgroPlast Ltd, a company that has been manufacturing net bags since 2015. These bags are used to transport and export mainly potatoes, but also fruits and vegetables are targeted.</p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column -->\n<!-- /wp:columns --><!-- wp:separator --><hr /><!-- /wp:separator --><!-- wp:columns -->\n<!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<!-- wp:image {\"id\":80,\"width\":\"104px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure><img style=\"width: 104px; height: auto;\" src=\"https://ciac.rw/wp-content/uploads/2024/01/cia.jpg\" alt=\"\" /></figure>\n<!-- /wp:image -->\n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 style=\"letter-spacing: 1px;\"><strong>NTIGURA Jean Ferdinand</strong></h4>\n<!-- /wp:heading --><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"><strong><em>BoD member, founder and Disciplinary Committee Vice President</em></strong></p>\n<!-- /wp:paragraph --><!-- wp:details {\"align\":\"wide\"} --><details>\n<summary><strong>Email:</strong><br />jntigura@gmail.com<br /><strong>Mobile/WhatsApp:</strong><br />+250 783 797 205 (Rw)<strong><br />Skype Name:</strong><br />Ntigura Jean Ferdinand<br /><strong>Languages: </strong><br />English, French, Kinyarwanda</summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p>Ferdinand holds Bachelor degree in Quantity Surveying and has over 10 years’ experience in construction industry. Registered, Member of Rwanda Institute of Quantity Surveyor (RIQS), Private and Personnel engaged in business activities. He worked with various construction companies, consultants and developers in Rwanda. He also worked as Civil Servant and holds Local Community responsibilities. Her gained experience and skills help in natural resource management, environmental protection, working with community and construction as well.</p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n \n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"> </p>\n<!-- /wp:paragraph --><!-- wp:details --><details>\n<summary></summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p> </p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column -->\n<!-- /wp:columns -->\n<!-- /wp:group -->\n<!-- /wp:group -->","Our Team","","inherit","closed","closed","","72-revision-v1","","","2025-10-28 08:46:20","2025-10-28 08:46:20","","72","https://ciac.rw/?p=152","0","revision","","0");
