em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<!-- wp:image {\"id\":80,\"width\":\"104px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure><img style=\"width: 104px; height: auto;\" src=\"https://ciac.rw/wp-content/uploads/2024/01/cia.jpg\" alt=\"\" /></figure>\n<!-- /wp:image -->\n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 style=\"letter-spacing: 1px;\"><strong>NTIGURA Jean Ferdinand</strong></h4>\n<!-- /wp:heading --><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"><strong><em>BoD member, founder and Disciplinary Committee Vice President</em></strong></p>\n<!-- /wp:paragraph --><!-- wp:details {\"align\":\"wide\"} --><details>\n<summary><strong>Email:</strong><br />jntigura@gmail.com<br /><strong>Mobile/WhatsApp:</strong><br />+250 783 797 205 (Rw)<strong><br />Skype Name:</strong><br />Ntigura Jean Ferdinand<br /><strong>Languages: </strong><br />English, French, Kinyarwanda</summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p>Ferdinand holds Bachelor degree in Quantity Surveying and has over 10 years’ experience in construction industry. Registered, Member of Rwanda Institute of Quantity Surveyor (RIQS), Private and Personnel engaged in business activities. He worked with various construction companies, consultants and developers in Rwanda. He also worked as Civil Servant and holds Local Community responsibilities. Her gained experience and skills help in natural resource management, environmental protection, working with community and construction as well.</p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n \n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"> </p>\n<!-- /wp:paragraph --><!-- wp:details --><details>\n<summary></summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p> </p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column -->\n<!-- /wp:columns -->\n<!-- /wp:group -->\n<!-- /wp:group -->		\n												<figure>\n										<img width=\"420\" height=\"420\" src=\"https://ciac.rw/wp-content/uploads/2024/04/drocel.jpeg\" alt=\"\" srcset=\"https://ciac.rw/wp-content/uploads/2024/04/drocel.jpeg 420w, https://ciac.rw/wp-content/uploads/2024/04/drocel-300x300.jpeg 300w, https://ciac.rw/wp-content/uploads/2024/04/drocel-150x150.jpeg 150w\" sizes=\"(max-width: 420px) 100vw, 420px\" />											<figcaption>Drocelle MUSABYIMANA, President of the BoD, Founder and Legal Representative</figcaption>\n										</figure>\n		<p>Drocella is a Water and Environmental Engineer and a Master\'s student in Environmental Science, nearing the completion of her studies. She leverages her expertise to drive sustainable development across Africa, with a strong passion for empowering small farmers, promoting wealth equality, and advancing financial inclusion. She believes that small farmers are the cornerstone of sustainable progress, where a bottom-up approach is essential. </p>\n<p>Currently, Drocelle serves as the Director of the Rwanda office at DIBcoop, an international business development organization. She previously worked with SHER-Rwanda, MDF, and other institutions, gaining valuable experience in natural resource management, environmental protection, construction, and farmer engagement. At DIBcoop, she contributes to the Rwanda team by leading community engagement initiatives, developing and implementing integrated water catchment management plans, and supporting monitoring and evaluation (M&amp;E) activities.</p>\n<p>Fluent in English, French, and Kinyarwanda, Drocelle works effectively across diverse communities and international teams.</p>\n<ul>\n<li><b>Email:</b> mudrocelle@gmail.com</li>\n<li><b>Mobile/WhatsApp:</b> (+250) 785 507 355</li>\n</ul><p>NTIGURA Jean Ferdinand is a BoD member, founder, and Vice President of the Disciplinary Committee, with over a decade of experience in the construction industry. He holds a Bachelor\'s degree in Quantity Surveying and is a registered member of the Rwanda Institute of Quantity Surveyors (RIQS).</p>\n<p>Ferdinand has worked with various construction companies, consultants, and developers across Rwanda and has served as a civil servant while taking on local community responsibilities. His extensive experience spans construction, natural resource management, environmental protection, and community engagement, providing him with a well-rounded perspective on sustainable development and effective project execution. </p>\n<p>Fluent in English, French, and Kinyarwanda, he effectively collaborates across professional and community contexts to drive impactful initiatives in Rwanda\'s construction and development sectors.</p>\n<p> </p>\n<ul>\n<li><b>Email:</b> jntigura@gmail.com</li>\n<li>Mobile/WhatsApp: (+250) 783 797 205</li>\n</ul>		\n												<figure>\n										<img width=\"768\" height=\"1024\" src=\"https://ciac.rw/wp-content/uploads/2024/01/cia-768x1024.jpg\" alt=\"\" srcset=\"https://ciac.rw/wp-content/uploads/2024/01/cia-768x1024.jpg 768w, https://ciac.rw/wp-content/uploads/2024/01/cia-225x300.jpg 225w, https://ciac.rw/wp-content/uploads/2024/01/cia.jpg 810w\" sizes=\"(max-width: 768px) 100vw, 768px\" />											<figcaption>Jean Ferdinand NTIGURA, BoD Member, Founder &amp; Disciplinary Committee Vice President</figcaption>\n										</figure>\n												<figure>\n										<img width=\"264\" height=\"274\" src=\"https://ciac.rw/wp-content/uploads/2024/01/IMG-1232_JPG.webp\" alt=\"\" />											<figcaption>Leon NDUWAYEZU, BoD Member, Founder and Disciplinary Committee Presindent</figcaption>\n										</figure>\n		<p>Leon NDUWAYEZU is an ambitious innovator dedicated to solving Rwanda\'s agricultural packaging challenges. Many smallholder farmers in Rwanda face difficulties transporting their fresh produce safely and securely across the country. With a strong background in strategic planning and marketing, Leon founded AgroPlast Ltd in 2015 to address this problem.</p>\n<p>AgroPlast specializes in manufacturing net bags that enable safe transport and export of potatoes, as well as a variety of fruits and vegetables. Through his work, Leon aims to strengthen Rwanda\'s agro-industry by providing practical, efficient solutions that empower smallholder farmers and improve the country\'s agricultural supply chain. </p>\n<p>Fluent in English, French, and Kinyarwanda, Leon collaborates effectively across diverse communities and business partners to drive innovation and impact in Rwanda\'s agricultural sector. </p>","Our Team","","inherit","closed","closed","","72-revision-v1","","","2025-10-28 08:46:20","2025-10-28 08:46:20","","72","https://ciac.rw/?p=154","0","revision","","0");
INSERT INTO `oJegmj1Sz_posts` VALUES("156","1","2025-10-28 08:49:21","2025-10-28 08:49:21","<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"60px\",\"right\":\"20px\",\"bottom\":\"60px\",\"left\":\"20px\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"align\":\"wide\",\"layout\":{\"type\":\"default\"}} -->\n<!-- wp:group {\"align\":\"wide\",\"className\":\"section_head\",\"layout\":{\"type\":\"default\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"}},\"className\":\"section_sub_title\",\"fontSize\":\"body-text\",\"fontFamily\":\"catamaran\"} -->\n<h4 style=\"font-style: normal; font-weight: 500;\">Our Team</h4>\n<!-- /wp:heading --><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\",\"fontSize\":\"40px\"}},\"className\":\"section_title\"} -->\n<h2 style=\"margin-top: 0px; font-size: 40px; font-style: normal; font-weight: bold;\">CIAC Experts</h2>\n<!-- /wp:heading --><!-- wp:spacer {\"height\":\"10px\"} -->\n \n<!-- /wp:spacer -->\n<!-- /wp:group --><!-- wp:columns -->\n<!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<!-- wp:image {\"id\":75,\"width\":\"104px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure><img style=\"width: 109px; height: 141px;\" src=\"https://ciac.rw/wp-content/uploads/2024/01/Drocella.png\" alt=\"\" /></figure>\n<!-- /wp:image -->\n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 style=\"letter-spacing: 1px;\"><strong>Drocelle Musabyimana</strong></h4>\n<!-- /wp:heading --><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"><strong><em>President of the BoD , founder and Legal Representative</em></strong></p>\n<!-- /wp:paragraph --><!-- wp:details {\"align\":\"wide\"} --><details>\n<summary><strong>Email:</strong><br />mudrocelle@gmail.com<br /><strong>Mobile/WhatsApp:</strong><br />+250 785 507 355 (Rw)<strong><br />Skype Name:</strong><br />Drocelle Musabyimana<br /><strong>Languages: </strong><br />English, French, Kinyarwanda</summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p>Drocelle is a Water and Environmental Engineer and Master’s student in Environmental Science ahead to completion. She uses her skills to contribute to the sustainable development of Africa, combining them with her interest in small farmer empowerment, wealth equality and financial inclusion. She believes that small farmers in Africa are the key to achieving sustainable development, for which a bottom-up approach is crucial. She is currently works with DIBcoop, an International Business development as Director Rwanda Office and she has previous worked with SHER-Rwanda, MDF among other where she gained experience in natural resource management, environmental protection, working with farmers and in construction. She contributes to the DIBcoop team in Rwanda by supporting community engagement processes, developing and implementing integrated water catchment plans, and assisting with M&amp;E reporting.</p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<!-- wp:image {\"id\":78,\"width\":\"118px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure><img style=\"width: 118px; height: auto;\" src=\"https://ciac.rw/wp-content/uploads/2024/01/IMG-1232_JPG.webp\" alt=\"\" /></figure>\n<!-- /wp:image -->\n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 style=\"letter-spacing: 1px;\">Nduwayezu Leon</h4>\n<!-- /wp:heading --><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"><strong><em>BoD member, founder and Disciplinary Committee President</em></strong></p>\n<!-- /wp:paragraph --><!-- wp:details --><details>\n<summary><strong>E-mail:</strong><br /><a href=\"mailto:nduluwa@yahoo.fr\">nduluwa@yahoo.fr</a><br /><strong>Mobile/WhatsApp:</strong><br /> (250)788300629<br /><strong>Languages: </strong><br />English, French, Kinyarwanda</summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p>Leon Nduwayezu is an ambitious innovator who aims to resolve Rwanda’s agricultural packaging problems. Currently, many small holder farmers in Rwanda struggle to deliver safely and securely their fresh produce across the country. With a background in strategic planning and marketing, Leon Nduwayezu has decided to end the packaging problem in Rwandan agro-industry sector by starting AgroPlast Ltd, a company that has been manufacturing net bags since 2015. These bags are used to transport and export mainly potatoes, but also fruits and vegetables are targeted.</p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column -->\n<!-- /wp:columns --><!-- wp:separator --><hr /><!-- /wp:separator --><!-- wp:columns -->\n<!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<!-- wp:image {\"id\":80,\"width\":\"104px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure><img style=\"width: 104px; height: auto;\" src=\"https://ciac.rw/wp-content/uploads/2024/01/cia.jpg\" alt=\"\" /></figure>\n<!-- /wp:image -->\n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 style=\"letter-spacing: 1px;\"><strong>NTIGURA Jean Ferdinand</strong></h4>\n<!-- /wp:heading --><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"><strong><em>BoD member, founder and Disciplinary Committee Vice President</em></strong></p>\n<!-- /wp:paragraph --><!-- wp:details {\"align\":\"wide\"} --><details>\n<summary><strong>Email:</strong><br />jntigura@gmail.com<br /><strong>Mobile/WhatsApp:</strong><br />+250 783 797 205 (Rw)<strong><br />Skype Name:</strong><br />Ntigura Jean Ferdinand<br /><strong>Languages: </strong><br />English, French, Kinyarwanda</summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p>Ferdinand holds Bachelor degree in Quantity Surveying and has over 10 years’ experience in construction industry. Registered, Member of Rwanda Institute of Quantity Surveyor (RIQS), Private and Personnel engaged in business activities. He worked with various construction companies, consultants and developers in Rwanda. He also worked as Civil Servant and holds Local Community responsibilities. Her gained experience and skills help in natural resource management, environmental protection, working with community and construction as well.</p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n \n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"> </p>\n<!-- /wp:paragraph --><!-- wp:details --><details>\n<summary></summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p> </p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column -->\n<!-- /wp:columns -->\n<!-- /wp:group -->\n<!-- /wp:group -->		\n												<figure>\n										<img width=\"420\" height=\"420\" src=\"https://ciac.rw/wp-content/uploads/2024/04/drocel.jpeg\" alt=\"\" srcset=\"https://ciac.rw/wp-content/uploads/2024/04/drocel.jpeg 420w, https://ciac.rw/wp-content/uploads/2024/04/drocel-300x300.jpeg 300w, https://ciac.rw/wp-content/uploads/2024/04/drocel-150x150.jpeg 150w\" sizes=\"(max-width: 420px) 100vw, 420px\" />											<figcaption>Drocelle MUSABYIMANA, President of the BoD, Founder and Legal Representative</figcaption>\n										</figure>\n		<p>Drocella is a Water and Environmental Engineer and a Master\'s student in Environmental Science, nearing the completion of her studies. She leverages her expertise to drive sustainable development across Africa, with a strong passion for empowering small farmers, promoting wealth equality, and advancing financial inclusion. She believes that small farmers are the cornerstone of sustainable progress, where a bottom-up approach is essential. </p>\n<p>Currently, Drocelle serves as the Director of the Rwanda office at DIBcoop, an international business development organization. She previously worked with SHER-Rwanda, MDF, and other institutions, gaining valuable experience in natural resource management, environmental protection, construction, and farmer engagement. At DIBcoop, she contributes to the Rwanda team by leading community engagement initiatives, developing and implementing integrated water catchment management plans, and supporting monitoring and evaluation (M&amp;E) activities.</p>\n<p>Fluent in English, French, and Kinyarwanda, Drocelle works effectively across diverse communities and international teams.</p>\n<ul>\n<li><b>Email:</b> mudrocelle@gmail.com</li>\n<li><b>Mobile/WhatsApp:</b> (+250) 785 507 355</li>\n</ul><p>NTIGURA Jean Ferdinand is a BoD member, founder, and Vice President of the Disciplinary Committee, with over a decade of experience in the construction industry. He holds a Bachelor\'s degree in Quantity Surveying and is a registered member of the Rwanda Institute of Quantity Surveyors (RIQS).</p>\n<p>Ferdinand has worked with various construction companies, consultants, and developers across Rwanda and has served as a civil servant while taking on local community responsibilities. His extensive experience spans construction, natural resource management, environmental protection, and community engagement, providing him with a well-rounded perspective on sustainable development and effective project execution. </p>\n<p>Fluent in English, French, and Kinyarwanda, he effectively collaborates across professional and community contexts to drive impactful initiatives in Rwanda\'s construction and development sectors.</p>\n<p> </p>\n<ul>\n<li><b>Email:</b> jntigura@gmail.com</li>\n<li>Mobile/WhatsApp: (+250) 783 797 205</li>\n</ul>		\n												<figure>\n										<img width=\"768\" height=\"1024\" src=\"https://ciac.rw/wp-content/uploads/2024/01/cia-768x1024.jpg\" alt=\"\" srcset=\"https://ciac.rw/wp-content/uploads/2024/01/cia-768x1024.jpg 768w, https://ciac.rw/wp-content/uploads/2024/01/cia-225x300.jpg 225w, https://ciac.rw/wp-content/uploads/2024/01/cia.jpg 810w\" sizes=\"(max-width: 768px) 100vw, 768px\" />											<figcaption>Jean Ferdinand NTIGURA, BoD Member, Founder &amp; Disciplinary Committee Vice President</figcaption>\n										</figure>\n												<figure>\n										<img width=\"264\" height=\"274\" src=\"https://ciac.rw/wp-content/uploads/2024/01/IMG-1232_JPG.webp\" alt=\"\" />											<figcaption>Leon NDUWAYEZU, BoD Member, Founder and Disciplinary Committee Presindent</figcaption>\n										</figure>\n		<p>Leon NDUWAYEZU is an ambitious innovator dedicated to solving Rwanda\'s agricultural packaging challenges. Many smallholder farmers in Rwanda face difficulties transporting their fresh produce safely and securely across the country. With a strong background in strategic planning and marketing, Leon founded AgroPlast Ltd in 2015 to address this problem.</p>\n<p>AgroPlast specializes in manufacturing net bags that enable safe transport and export of potatoes, as well as a variety of fruits and vegetables. Through his work, Leon aims to strengthen Rwanda\'s agro-industry by providing practical, efficient solutions that empower smallholder farmers and improve the country\'s agricultural supply chain. </p>\n<p>Fluent in English, French, and Kinyarwanda, Leon collaborates effectively across diverse communities and business partners to drive innovation and impact in Rwanda\'s agricultural sector. </p>","Our Team","","inherit","closed","closed","","72-revision-v1","","","2025-10-28 08:49:21","2025-10-28 08:49:21","","72","https://ciac.rw/?p=156","0","revision","","0");
INSERT INTO `oJegmj1Sz_posts` VALUES("157","1","2025-10-28 08:49:21","2025-10-28 08:49:21","<!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"60px\",\"right\":\"20px\",\"bottom\":\"60px\",\"left\":\"20px\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"align\":\"wide\",\"layout\":{\"type\":\"default\"}} -->\n<!-- wp:group {\"align\":\"wide\",\"className\":\"section_head\",\"layout\":{\"type\":\"default\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"}},\"className\":\"section_sub_title\",\"fontSize\":\"body-text\",\"fontFamily\":\"catamaran\"} -->\n<h4 style=\"font-style: normal; font-weight: 500;\">Our Team</h4>\n<!-- /wp:heading --><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\",\"fontSize\":\"40px\"}},\"className\":\"section_title\"} -->\n<h2 style=\"margin-top: 0px; font-size: 40px; font-style: normal; font-weight: bold;\">CIAC Experts</h2>\n<!-- /wp:heading --><!-- wp:spacer {\"height\":\"10px\"} -->\n \n<!-- /wp:spacer -->\n<!-- /wp:group --><!-- wp:columns -->\n<!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<!-- wp:image {\"id\":75,\"width\":\"104px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure><img style=\"width: 109px; height: 141px;\" src=\"https://ciac.rw/wp-content/uploads/2024/01/Drocella.png\" alt=\"\" /></figure>\n<!-- /wp:image -->\n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 style=\"letter-spacing: 1px;\"><strong>Drocelle Musabyimana</strong></h4>\n<!-- /wp:heading --><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"><strong><em>President of the BoD , founder and Legal Representative</em></strong></p>\n<!-- /wp:paragraph --><!-- wp:details {\"align\":\"wide\"} --><details>\n<summary><strong>Email:</strong><br />mudrocelle@gmail.com<br /><strong>Mobile/WhatsApp:</strong><br />+250 785 507 355 (Rw)<strong><br />Skype Name:</strong><br />Drocelle Musabyimana<br /><strong>Languages: </strong><br />English, French, Kinyarwanda</summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p>Drocelle is a Water and Environmental Engineer and Master’s student in Environmental Science ahead to completion. She uses her skills to contribute to the sustainable development of Africa, combining them with her interest in small farmer empowerment, wealth equality and financial inclusion. She believes that small farmers in Africa are the key to achieving sustainable development, for which a bottom-up approach is crucial. She is currently works with DIBcoop, an International Business development as Director Rwanda Office and she has previous worked with SHER-Rwanda, MDF among other where she gained experience in natural resource management, environmental protection, working with farmers and in construction. She contributes to the DIBcoop team in Rwanda by supporting community engagement processes, developing and implementing integrated water catchment plans, and assisting with M&amp;E reporting.</p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<!-- wp:image {\"id\":78,\"width\":\"118px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure><img style=\"width: 118px; height: auto;\" src=\"https://ciac.rw/wp-content/uploads/2024/01/IMG-1232_JPG.webp\" alt=\"\" /></figure>\n<!-- /wp:image -->\n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 style=\"letter-spacing: 1px;\">Nduwayezu Leon</h4>\n<!-- /wp:heading --><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"><strong><em>BoD member, founder and Disciplinary Committee President</em></strong></p>\n<!-- /wp:paragraph --><!-- wp:details --><details>\n<summary><strong>E-mail:</strong><br /><a href=\"mailto:nduluwa@yahoo.fr\">nduluwa@yahoo.fr</a><br /><strong>Mobile/WhatsApp:</strong><br /> (250)788300629<br /><strong>Languages: </strong><br />English, French, Kinyarwanda</summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p>Leon Nduwayezu is an ambitious innovator who aims to resolve Rwanda’s agricultural packaging problems. Currently, many small holder farmers in Rwanda struggle to deliver safely and securely their fresh produce across the country. With a background in strategic planning and marketing, Leon Nduwayezu has decided to end the packaging problem in Rwandan agro-industry sector by starting AgroPlast Ltd, a company that has been manufacturing net bags since 2015. These bags are used to transport and export mainly potatoes, but also fruits and vegetables are targeted.</p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column -->\n<!-- /wp:columns --><!-- wp:separator --><hr /><!-- /wp:separator --><!-- wp:columns -->\n<!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n<!-- wp:image {\"id\":80,\"width\":\"104px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"align\":\"center\",\"className\":\"is-style-rounded\"} -->\n<figure><img style=\"width: 104px; height: auto;\" src=\"https://ciac.rw/wp-content/uploads/2024/01/cia.jpg\" alt=\"\" /></figure>\n<!-- /wp:image -->\n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4,\"style\":{\"typography\":{\"letterSpacing\":\"1px\"}},\"fontSize\":\"regular\"} -->\n<h4 style=\"letter-spacing: 1px;\"><strong>NTIGURA Jean Ferdinand</strong></h4>\n<!-- /wp:heading --><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"><strong><em>BoD member, founder and Disciplinary Committee Vice President</em></strong></p>\n<!-- /wp:paragraph --><!-- wp:details {\"align\":\"wide\"} --><details>\n<summary><strong>Email:</strong><br />jntigura@gmail.com<br /><strong>Mobile/WhatsApp:</strong><br />+250 783 797 205 (Rw)<strong><br />Skype Name:</strong><br />Ntigura Jean Ferdinand<br /><strong>Languages: </strong><br />English, French, Kinyarwanda</summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p>Ferdinand holds Bachelor degree in Quantity Surveying and has over 10 years’ experience in construction industry. Registered, Member of Rwanda Institute of Quantity Surveyor (RIQS), Private and Personnel engaged in business activities. He worked with various construction companies, consultants and developers in Rwanda. He also worked as Civil Servant and holds Local Community responsibilities. Her gained experience and skills help in natural resource management, environmental protection, working with community and construction as well.</p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"50px\",\"right\":\"2.5em\",\"bottom\":\"70px\",\"left\":\"2.5em\"}},\"color\":{\"background\":\"#f3faf8\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"10px\",\"right\":\"10px\",\"bottom\":\"10px\",\"left\":\"10px\"}},\"border\":{\"radius\":\"50{3338937df10194424d40636f8c2716dc2160f64fc18487a5744941c2d65e9ddb}\",\"width\":\"2px\"}},\"borderColor\":\"cyan-bluish-gray\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"\"}} -->\n \n<!-- /wp:group -->\n<!-- /wp:group --><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"},\"padding\":{\"top\":\"20px\",\"right\":\"20px\",\"bottom\":\"20px\",\"left\":\"20px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\"}}},\"textColor\":\"primary\"} -->\n<p style=\"margin-top: 10px;\"> </p>\n<!-- /wp:paragraph --><!-- wp:details --><details>\n<summary></summary>\n<!-- wp:paragraph {\"placeholder\":\"Type / to add a hidden block\"} -->\n<p> </p>\n<!-- /wp:paragraph --></details><!-- /wp:details -->\n<!-- /wp:group -->\n<!-- /wp:group -->\n<!-- /wp:column --><!-- wp:column -->\n<!-- wp:group {\"className\":\"shadow\",\"layout\":{\"type\":\"constrained\"}} -->\n<!-- wp:paragraph -->\n<p> </p>\n<!-- /wp:paragraph -->\n<!-- /wp:group -->\n<!-- /wp:column -->\n<!-- /wp:columns -->\n<!-- /wp:group -->\n<!-- /wp:group -->		\n												<figure>\n										<img width=\"420\" height=\"420\" src=\"https://ciac.rw/wp-content/uploads/2024/04/drocel.jpeg\" alt=\"\" srcset=\"https://ciac.rw/wp-content/uploads/2024/04/drocel.jpeg 420w, https://ciac.rw/wp-content/uploads/2024/04/drocel-300x300.jpeg 300w, https://ciac.rw/wp-content/uploads/2024/04/drocel-150x150.jpeg 150w\" sizes=\"(max-width: 420px) 100vw, 420px\" />											<figcaption>Drocelle MUSABYIMANA, President of the BoD, Founder and Legal Representative</figcaption>\n										</figure>\n		<p>Drocella is a Water and Environmental Engineer and a Master\'s student in Environmental Science, nearing the completion of her studies. She leverages her expertise to drive sustainable development across Africa, with a strong passion for empowering small farmers, promoting wealth equality, and advancing financial inclusion. She believes that small farmers are the cornerstone of sustainable progress, where a bottom-up approach is essential. </p>\n<p>Currently, Drocelle serves as the Director of the Rwanda office at DIBcoop, an international business development organization. She previously worked with SHER-Rwanda, MDF, and other institutions, gaining valuable experience in natural resource management, environmental protection, construction, and farmer engagement. At DIBcoop, she contributes to the Rwanda team by leading community engagement initiatives, developing and implementing integrated water catchment management plans, and supporting monitoring and evaluation (M&amp;E) activities.</p>\n<p>Fluent in English, French, and Kinyarwanda, Drocelle works effectively across diverse communities and international teams.</p>\n<ul>\n<li><b>Email:</b> mudrocelle@gmail.com</li>\n<li><b>Mobile/WhatsApp:</b> (+250) 785 507 355</li>\n</ul><p>NTIGURA Jean Ferdinand is a BoD member, founder, and Vice President of the Disciplinary Committee, with over a decade of experience in the construction industry. He holds a Bachelor\'s degree in Quantity Surveying and is a registered member of the Rwanda Institute of Quantity Surveyors (RIQS).</p>\n<p>Ferdinand has worked with various construction companies, consultants, and developers across Rwanda and has served as a civil servant while taking on local community responsibilities. His extensive experience spans construction, natural resource management, environmental protection, and community engagement, providing him with a well-rounded perspective on sustainable development and effective project execution. </p>\n<p>Fluent in English, French, and Kinyarwanda, he effectively collaborates across professional and community contexts to drive impactful initiatives in Rwanda\'s construction and development sectors.</p>\n<p> </p>\n<ul>\n<li><b>Email:</b> jntigura@gmail.com</li>\n<li>Mobile/WhatsApp: (+250) 783 797 205</li>\n</ul>		\n												<figure>\n										<img width=\"768\" height=\"1024\" src=\"https://ciac.rw/wp-content/uploads/2024/01/cia-768x1024.jpg\" alt=\"\" srcset=\"https://ciac.rw/wp-content/uploads/2024/01/cia-768x1024.jpg 768w, https://ciac.rw/wp-content/uploads/2024/01/cia-225x300.jpg 225w, https://ciac.rw/wp-content/uploads/2024/01/cia.jpg 810w\" sizes=\"(max-width: 768px) 100vw, 768px\" />											<figcaption>Jean Ferdinand NTIGURA, BoD Member, Founder &amp; Disciplinary Committee Vice President</figcaption>\n										</figure>\n												<figure>\n										<img width=\"264\" height=\"274\" src=\"https://ciac.rw/wp-content/uploads/2024/01/IMG-1232_JPG.webp\" alt=\"\" />											<figcaption>Leon NDUWAYEZU, BoD Member, Founder and Disciplinary Committee Presindent</figcaption>\n										</figure>\n		<p>Leon NDUWAYEZU is an ambitious innovator dedicated to solving Rwanda\'s agricultural packaging challenges. Many smallholder farmers in Rwanda face difficulties transporting their fresh produce safely and securely across the country. With a strong background in strategic planning and marketing, Leon founded AgroPlast Ltd in 2015 to address this problem.</p>\n<p>AgroPlast specializes in manufacturing net bags that enable safe transport and export of potatoes, as well as a variety of fruits and vegetables. Through his work, Leon aims to strengthen Rwanda\'s agro-industry by providing practical, efficient solutions that empower smallholder farmers and improve the country\'s agricultural supply chain. </p>\n<p>Fluent in English, French, and Kinyarwanda, Leon collaborates effectively across diverse communities and business partners to drive innovation and impact in Rwanda\'s agricultural sector. </p>","Our Team","","inherit","closed","closed","","72-revision-v1","","","2025-10-28 08:49:21","2025-10-28 08:49:21","","72","https://ciac.rw/?p=157","0","revision","","0");
